// src/pages/ResultsPage.js
import React, { useEffect, useState, useRef } from 'react';
import { useParams, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import {
  RadarChart, Radar, PolarGrid, PolarAngleAxis, ResponsiveContainer,
  BarChart, Bar, XAxis, YAxis, Tooltip, CartesianGrid
} from 'recharts';
import Navbar from '../components/common/Navbar';
import api from '../services/api';
import toast from 'react-hot-toast';
import {
  FiDownload, FiArrowLeft, FiCheckCircle, FiXCircle,
  FiAlertCircle, FiBook, FiStar
} from 'react-icons/fi';

function ScoreRing({ score, label, color }) {
  const r = 54;
  const circ = 2 * Math.PI * r;
  const dash = ((score || 0) / 100) * circ;
  return (
    <div className="flex flex-col items-center">
      <div className="relative w-32 h-32">
        <svg width="128" height="128" viewBox="0 0 128 128">
          <circle cx="64" cy="64" r={r} fill="none" stroke="#1e293b" strokeWidth="10" />
          <circle cx="64" cy="64" r={r} fill="none" stroke={color} strokeWidth="10"
            strokeDasharray={`${dash} ${circ}`} strokeDashoffset={circ / 4}
            strokeLinecap="round" style={{ transition: 'stroke-dasharray 1s ease' }} />
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className="text-2xl font-bold text-white">{(score || 0).toFixed(0)}%</span>
        </div>
      </div>
      <p className="text-sm text-slate-400 mt-2">{label}</p>
    </div>
  );
}

export default function ResultsPage() {
  const { id } = useParams();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState('overview');
  const [generating, setGenerating] = useState(false);
  const [speaking, setSpeaking] = useState(false);

  useEffect(() => {
    api.get(`/results/${id}`)
      .then(res => setData(res.data))
      .catch(() => toast.error('Failed to load results'))
      .finally(() => setLoading(false));
    return () => { if (window.speechSynthesis) window.speechSynthesis.cancel(); };
  }, [id]);

  const speakSummary = () => {
    if (!window.speechSynthesis) { toast.error('Browser does not support text-to-speech'); return; }
    if (speaking) { window.speechSynthesis.cancel(); setSpeaking(false); return; }
    const result = data?.result;
    const feedback = data?.feedback;
    const interview = data?.interview;
    const text = [
      `Interview Results for ${interview?.job_role}.`,
      `Your overall score is ${(result?.overall_percentage || 0).toFixed(0)} percent. Grade: ${result?.grade}.`,
      `Technical round: ${(result?.technical_percentage || 0).toFixed(0)} percent.`,
      `HR round: ${(result?.hr_percentage || 0).toFixed(0)} percent.`,
      feedback?.overall_summary ? `AI Feedback: ${feedback.overall_summary}` : '',
      feedback?.strengths?.length ? `Your strengths are: ${feedback.strengths.join(', ')}.` : '',
      feedback?.weaknesses?.length ? `Areas to improve: ${feedback.weaknesses.join(', ')}.` : '',
      feedback?.technical_gaps?.length ? `Technical gaps to study: ${feedback.technical_gaps.join(', ')}.` : '',
    ].filter(Boolean).join(' ');
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.rate = 0.95; utterance.pitch = 1; utterance.volume = 1;
    const voices = window.speechSynthesis.getVoices();
    const preferred = voices.find(v => v.name.includes('Google') || v.lang === 'en-US');
    if (preferred) utterance.voice = preferred;
    utterance.onstart = () => setSpeaking(true);
    utterance.onend = () => setSpeaking(false);
    utterance.onerror = () => setSpeaking(false);
    window.speechSynthesis.speak(utterance);
  };

  const downloadReport = async () => {
    setGenerating(true);
    try {
      await api.post(`/reports/generate/${id}`);
      const res = await api.get(`/reports/download/${id}`, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([res.data]));
      const a = document.createElement('a'); a.href = url;
      a.download = `interview_report_${id}.pdf`; a.click();
      window.URL.revokeObjectURL(url);
      toast.success('Report downloaded!');
    } catch { toast.error('Failed to generate report'); }
    finally { setGenerating(false); }
  };

  if (loading) return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center">
      <div className="w-8 h-8 border-2 border-primary-500 border-t-transparent rounded-full animate-spin" />
    </div>
  );
  if (!data) return null;

  const { interview, result, feedback, qa_review, violations } = data;
  const grade = result?.grade || 'F';
  const gradeColor = grade.startsWith('A') ? 'text-emerald-400' : grade === 'B+' || grade === 'B' ? 'text-yellow-400' : 'text-red-400';
  const skillData = result?.skill_scores
    ? Object.entries(result.skill_scores).map(([k, v]) => ({ skill: k.length > 10 ? k.slice(0,10)+'…' : k, score: v.percentage || 0 }))
    : [];
  const tabClass = (t) => `px-4 py-2 rounded-lg text-sm font-medium transition-all ${tab === t ? 'bg-primary-600 text-white' : 'text-slate-400 hover:text-white'}`;

  return (
    <div className="min-h-screen bg-slate-950 text-white">
      <Navbar />
      <div className="max-w-5xl mx-auto px-4 sm:px-6 pt-24 pb-16">
        <motion.div initial={{ opacity: 0, y: 16 }} animate={{ opacity: 1, y: 0 }} className="mb-8">
          <Link to="/dashboard" className="flex items-center gap-2 text-slate-400 hover:text-white text-sm mb-4 transition-colors">
            <FiArrowLeft size={14} /> Back to Dashboard
          </Link>
          <div className="flex items-start justify-between flex-wrap gap-4">
            <div>
              <h1 className="text-3xl font-display font-bold text-white">Interview Results</h1>
              <p className="text-slate-400 mt-1">{interview?.job_role} · {interview?.created_at ? new Date(interview.created_at).toLocaleDateString('en-IN', { day:'numeric', month:'long', year:'numeric' }) : ''}</p>
            </div>
            <div className="flex items-center gap-3 flex-wrap">
              <button onClick={speakSummary}
                className={`flex items-center gap-2 px-4 py-2.5 rounded-xl text-sm font-medium transition-all border ${speaking ? 'bg-yellow-600/20 border-yellow-600/40 text-yellow-300 animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-300 hover:text-white'}`}>
                {speaking ? '🔊 Stop Voice' : '🔊 Hear Summary'}
              </button>
              <button onClick={downloadReport} disabled={generating}
                className="flex items-center gap-2 bg-primary-600 hover:bg-primary-500 disabled:opacity-50 text-white px-5 py-2.5 rounded-xl text-sm font-medium transition-all">
                {generating ? <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" /> : <FiDownload />}
                {generating ? 'Generating...' : 'Download PDF'}
              </button>
            </div>
          </div>
        </motion.div>

        {result && (
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }}
            className="bg-slate-900 border border-slate-800 rounded-2xl p-8 mb-6 flex flex-wrap items-center justify-around gap-6">
            <ScoreRing score={result.technical_percentage} label="Technical" color="#6366f1" />
            <div className="text-center">
              <div className={`text-6xl font-display font-bold ${gradeColor}`}>{grade}</div>
              <p className="text-slate-400 text-sm mt-2">Overall Grade</p>
              <p className="text-2xl font-bold text-white mt-1">{(result.overall_percentage || 0).toFixed(1)}%</p>
            </div>
            <ScoreRing score={result.hr_percentage} label="HR Round" color="#10b981" />
          </motion.div>
        )}

        <div className="flex gap-2 mb-6 flex-wrap">
          {['overview','review','feedback','violations'].map(t => (
            <button key={t} onClick={() => setTab(t)} className={tabClass(t)}>
              {t.charAt(0).toUpperCase()+t.slice(1)}
            </button>
          ))}
        </div>

        {tab === 'overview' && result && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-6">
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
              {[
                { label:'Correct', value:(result.technical_correct||0)+(result.hr_correct||0), icon:<FiCheckCircle className="text-emerald-400"/>, color:'text-emerald-400' },
                { label:'Wrong', value:(result.technical_wrong||0)+(result.hr_wrong||0), icon:<FiXCircle className="text-red-400"/>, color:'text-red-400' },
                { label:'Skipped', value:(result.technical_skipped||0)+(result.hr_skipped||0), icon:<FiAlertCircle className="text-yellow-400"/>, color:'text-yellow-400' },
                { label:'Violations', value:violations?.length||0, icon:<FiAlertCircle className="text-orange-400"/>, color:'text-orange-400' },
              ].map((s,i) => (
                <div key={i} className="bg-slate-900 border border-slate-800 rounded-xl p-4 flex items-center gap-3">
                  {s.icon}<div><p className={`text-xl font-bold ${s.color}`}>{s.value}</p><p className="text-xs text-slate-400">{s.label}</p></div>
                </div>
              ))}
            </div>
            {skillData.length > 2 && (
              <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6">
                <h3 className="font-semibold text-white mb-4">Skill-wise Performance</h3>
                <ResponsiveContainer width="100%" height={260}>
                  <RadarChart data={skillData}>
                    <PolarGrid stroke="#1e293b" />
                    <PolarAngleAxis dataKey="skill" tick={{ fill:'#64748b', fontSize:11 }} />
                    <Radar name="Score" dataKey="score" stroke="#6366f1" fill="#6366f1" fillOpacity={0.2} strokeWidth={2} />
                  </RadarChart>
                </ResponsiveContainer>
              </div>
            )}
            {skillData.length > 0 && (
              <div className="bg-slate-900 border border-slate-800 rounded-2xl p-6">
                <h3 className="font-semibold text-white mb-4">Score by Topic</h3>
                <ResponsiveContainer width="100%" height={200}>
                  <BarChart data={skillData} margin={{ top:5, right:10, left:-20, bottom:5 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1e293b" />
                    <XAxis dataKey="skill" tick={{ fill:'#64748b', fontSize:10 }} />
                    <YAxis domain={[0,100]} tick={{ fill:'#64748b', fontSize:10 }} />
                    <Tooltip contentStyle={{ background:'#0f172a', border:'1px solid #1e293b', borderRadius:'8px', color:'#fff' }} formatter={v=>[`${v}%`]} />
                    <Bar dataKey="score" fill="#6366f1" radius={[4,4,0,0]} />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            )}
            <div className="grid sm:grid-cols-2 gap-4">
              {[
                { label:'Technical Round', total:result.technical_total, correct:result.technical_correct, wrong:result.technical_wrong, skipped:result.technical_skipped, pct:result.technical_percentage, color:'#6366f1' },
                { label:'HR Round', total:result.hr_total, correct:result.hr_correct, wrong:result.hr_wrong, skipped:result.hr_skipped, pct:result.hr_percentage, color:'#10b981' },
              ].map((r,i) => (
                <div key={i} className="bg-slate-900 border border-slate-800 rounded-xl p-5">
                  <div className="flex items-center justify-between mb-3">
                    <h4 className="font-medium text-white">{r.label}</h4>
                    <span className="text-lg font-bold" style={{ color:r.color }}>{(r.pct||0).toFixed(1)}%</span>
                  </div>
                  <div className="w-full h-2 bg-slate-800 rounded-full mb-3">
                    <div className="h-full rounded-full" style={{ width:`${r.pct||0}%`, background:r.color }} />
                  </div>
                  <div className="flex gap-4 text-xs">
                    <span className="text-emerald-400">✓ {r.correct||0} correct</span>
                    <span className="text-red-400">✗ {r.wrong||0} wrong</span>
                    <span className="text-yellow-400">— {r.skipped||0} skipped</span>
                  </div>
                </div>
              ))}
            </div>
          </motion.div>
        )}

        {tab === 'review' && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-4">
            {qa_review?.map((q, i) => (
              <div key={q.id} className={`bg-slate-900 border rounded-xl p-5 ${q.is_correct ? 'border-emerald-800/40' : q.selected_answer==='skipped' ? 'border-slate-700' : 'border-red-800/40'}`}>
                <div className="flex items-start justify-between gap-3 mb-3">
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="text-xs text-slate-500">Q{i+1}</span>
                    {q.skill_tag && <span className="text-xs bg-slate-800 text-slate-400 px-2 py-0.5 rounded-full">{q.skill_tag}</span>}
                    <span className={`text-xs px-2 py-0.5 rounded-full ${q.question_type==='technical' ? 'bg-primary-600/20 text-primary-400' : 'bg-emerald-600/20 text-emerald-400'}`}>{q.question_type}</span>
                  </div>
                  {q.is_correct ? <FiCheckCircle className="text-emerald-400"/> : q.selected_answer==='skipped' ? <FiAlertCircle className="text-yellow-400"/> : <FiXCircle className="text-red-400"/>}
                </div>
                <p className="text-sm text-white mb-3">{q.question_text}</p>
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  {['A','B','C','D'].map(opt => {
                    const optText = q[`option_${opt.toLowerCase()}`];
                    const isCorrect = q.correct_answer===opt;
                    const isSelected = q.selected_answer===opt;
                    return (
                      <div key={opt} className={`text-xs px-3 py-2 rounded-lg border flex items-center gap-2 ${isCorrect ? 'border-emerald-600/50 bg-emerald-600/10 text-emerald-300' : isSelected&&!isCorrect ? 'border-red-600/50 bg-red-600/10 text-red-300' : 'border-slate-700 text-slate-400'}`}>
                        <span className="font-bold">{opt}.</span> {optText}
                        {isCorrect && <FiCheckCircle className="ml-auto text-emerald-400 flex-shrink-0" size={12}/>}
                        {isSelected&&!isCorrect && <FiXCircle className="ml-auto text-red-400 flex-shrink-0" size={12}/>}
                      </div>
                    );
                  })}
                </div>
                {q.selected_answer==='skipped' && <p className="text-xs text-yellow-400 mt-2">⏭ Skipped — Correct: {q.correct_answer}</p>}
              </div>
            ))}
          </motion.div>
        )}

        {tab === 'feedback' && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-6">
            {!feedback ? <p className="text-slate-400 text-center py-12">AI feedback is being generated. Refresh in a moment.</p> : (
              <>
                {feedback.overall_summary && (
                  <div className="bg-slate-900 border border-slate-800 rounded-xl p-6">
                    <h3 className="font-semibold text-white mb-2 flex items-center gap-2"><FiStar className="text-yellow-400"/>Overall Assessment</h3>
                    <p className="text-slate-300 text-sm leading-relaxed">{feedback.overall_summary}</p>
                  </div>
                )}
                <div className="grid sm:grid-cols-2 gap-4">
                  {feedback.strengths?.length > 0 && (
                    <div className="bg-emerald-950/40 border border-emerald-800/30 rounded-xl p-5">
                      <h3 className="font-semibold text-emerald-300 mb-3">✓ Strengths</h3>
                      <ul className="space-y-2">{feedback.strengths.map((s,i) => <li key={i} className="text-sm text-emerald-200/70 flex items-start gap-2"><span className="mt-1 w-1 h-1 bg-emerald-400 rounded-full flex-shrink-0"/>{s}</li>)}</ul>
                    </div>
                  )}
                  {feedback.weaknesses?.length > 0 && (
                    <div className="bg-red-950/40 border border-red-800/30 rounded-xl p-5">
                      <h3 className="font-semibold text-red-300 mb-3">⚠ Areas to Improve</h3>
                      <ul className="space-y-2">{feedback.weaknesses.map((w,i) => <li key={i} className="text-sm text-red-200/70 flex items-start gap-2"><span className="mt-1 w-1 h-1 bg-red-400 rounded-full flex-shrink-0"/>{w}</li>)}</ul>
                    </div>
                  )}
                </div>
                {feedback.technical_gaps?.length > 0 && (
                  <div className="bg-slate-900 border border-slate-800 rounded-xl p-5">
                    <h3 className="font-semibold text-white mb-3 flex items-center gap-2"><FiBook className="text-blue-400"/>Technical Gaps</h3>
                    <div className="flex flex-wrap gap-2">{feedback.technical_gaps.map((g,i) => <span key={i} className="text-xs bg-blue-600/20 text-blue-300 px-3 py-1 rounded-full border border-blue-600/30">{g}</span>)}</div>
                  </div>
                )}
                {feedback.resume_suggestions?.length > 0 && (
                  <div className="bg-slate-900 border border-slate-800 rounded-xl p-5">
                    <h3 className="font-semibold text-white mb-3">📄 Resume Suggestions</h3>
                    <ul className="space-y-2">{feedback.resume_suggestions.map((s,i) => <li key={i} className="text-sm text-slate-300 flex items-start gap-2"><span className="text-primary-400 mt-0.5">→</span>{s.suggestion||s}</li>)}</ul>
                  </div>
                )}
                {feedback.learning_roadmap?.length > 0 && (
                  <div className="bg-slate-900 border border-slate-800 rounded-xl p-5">
                    <h3 className="font-semibold text-white mb-4">🗺 Learning Roadmap</h3>
                    <div className="space-y-3">{feedback.learning_roadmap.map((week,i) => (
                      <div key={i} className="flex gap-4">
                        <div className="w-14 flex-shrink-0"><span className="text-xs bg-primary-600/20 text-primary-300 px-2 py-1 rounded-lg">Wk {week.week}</span></div>
                        <div><p className="text-sm font-medium text-white">{week.focus}</p>{week.resources?.map((r,j) => <p key={j} className="text-xs text-slate-400 mt-0.5">• {r}</p>)}</div>
                      </div>
                    ))}</div>
                  </div>
                )}
              </>
            )}
          </motion.div>
        )}

        {tab === 'violations' && (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
            {!violations?.length ? (
              <div className="text-center py-12 text-slate-400"><FiCheckCircle size={40} className="mx-auto mb-3 text-emerald-400"/><p>No violations detected. Clean interview!</p></div>
            ) : (
              <div className="space-y-3">{violations.map((v,i) => (
                <div key={i} className="bg-red-950/30 border border-red-800/30 rounded-xl p-4 flex items-center justify-between">
                  <div><p className="text-sm font-medium text-red-300">{v.type.replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase())}</p><p className="text-xs text-slate-400 mt-0.5">{v.description||'—'}</p></div>
                  <span className="text-xs text-slate-500">{new Date(v.time).toLocaleTimeString()}</span>
                </div>
              ))}</div>
            )}
          </motion.div>
        )}
      </div>
    </div>
  );
}
